mapper.select:
SELECT Top 1000 Row_Number()OVER(ORDER BY Identifier, ClassCode) as RNUM , 0 AS CHK , ItemTypeImg , ItemID, Path, ItemName, ClassName, ClassCode, TeamName , OwnerTeamName, Name, LastUpdated,Version, Identifier , StatusName , 'btn_import_small.gif' As Report , CreationTime FROM ( SELECT DISTINCT TI.ItemID , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , ISNULL(XBOLTADM.fn_GetMyAbsPathForList( TI.ItemID ,#{languageID}),'') AS Path , ISNULL(TIA.PlainText,'') as ItemName , TD.Name as ClassName, TI.ClassCode , ISNULL(TT.Name, '') as TeamName , TOT.Name as OwnerTeamName , TM.Name, TI.Version, TI.Identifier , TSD.Name AS StatusName , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated , Convert(nvarchar(20),TI.CreationTime, 111) AS CreationTime FROM XBOLTADM.TB_ITEM TI
Left Outer JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} Left outer join XBOLTADM.TB_DICTIONARY TSD on TI.Status = TSD.TypeCode AND TSD.LanguageID = #{languageID} AND TSD.Category = 'ITMSTS' Left outer join XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID} Left outer join XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} Left outer join XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
Left Outer JOIN XBOLTADM.TB_ITEM_DIM TID ON TI.ItemID = TID.ItemID
WHERE TI.Deleted != 1
AND TI.ItemID IN ( SELECT DISTINCT ItemID FROM XBOLTADM.TB_ITEM_ATTR WHERE AttrTypeCode = #{item.attrCode}
AND PlainText
NOT like '%'+#{item.searchValue}+'%'
AND PlainText
not like '%'+#{item.searchValue}+'%'ESCAPE'!'
AND LanguageID = #{languageID}
AND LanguageID = #{defaultLang}
)
AND TI.ItemID IN ( SELECT DISTINCT ItemID FROM XBOLTADM.TB_ITEM_ATTR WHERE LovCode = #{lovCode} AND AttrTypeCode = #{item}
AND LanguageID = #{languageID}
AND LanguageID = #{defaultLang}
)
AND TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM WHERE Identifier
not
like '%'+#{searchValue}+'%' )
AND TI.ItemID IN ( SELECT DISTINCT ItemID FROM XBOLTADM.TB_ITEM_ATTR WHERE PlainText like '%'+#{baseCondition1}+'%' AND AttrTypeCode = #{AttrCodeBase1} AND LanguageID = #{languageID} )
AND TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM WHERE
Identifier like '%'+#{baseCondition2}+'%'ESCAPE'!' Identifier like '%'+#{baseCondition2}+'%'
)
AND TI.CategoryCode = #{CategoryCode}
AND TI.ClassCode = #{ClassCode}
AND TI.ItemTypeCode = #{ItemTypeCode}
AND TI.ItemID IN (${childItems})
AND TI.ItemID IN ('')
AND TI.ItemID NOT IN (${masterItemId})
AND TID.DimValueID = #{DimValueID}
AND TID.DimTypeID = #{DimTypeID}
AND TI.CompanyID = #{CompanyID}
AND TOT.Name like '%'+#{OwnerTeam}+'%'ESCAPE'!'
AND TOT.Name like '%'+#{OwnerTeam}+'%'
AND TM.Name like '%'+#{Name}+'%'ESCAPE'!'
AND TM.Name like '%'+#{Name}+'%'
AND TI.Status = #{Status}
AND TI.Identifier IS NOT NULL AND TI.Identifier != ''
AND TI.DefSymCode = #{DefSymCode}
AND CONVERT(nvarchar(20), TI.CreationTime, 112) BETWEEN #{scStartDt1} AND #{scEndDt1}
AND CONVERT(nvarchar(20), TI.LastUpdated, 112) BETWEEN #{scStartDt2} AND #{scEndDt2}
AND TI.ItemID IN ( SELECT distinct ItemID FROM XBOLTADM.TB_ITEM_ATTR WHERE AttrTypeCode = #{AttrCode} AND LanguageID = #{languageID}
AND ClassCode = #{ClassCode}
AND ItemID IN(${childItems})
AND ItemID IN ('')
)
AND TI.ItemID NOT IN ( SELECT distinct ItemID FROM XBOLTADM.TB_ITEM_ATTR WHERE AttrTypeCode = #{AttrCode} AND LanguageID = #{languageID}
AND ClassCode = #{ClassCode}
AND ItemID IN (${childItems})
AND ItemID IN ('')
)
) A 1=1
AND A.RNUM BETWEEN ((#{pageNo}-1)*#{LIST_PAGE_SCALE} + 1) AND (#{pageNo}*#{LIST_PAGE_SCALE})
AND ItemID NOT IN (select ItemID FROM XBOLTADM.TB_ITEM_DIM WHERE DimTypeID = #{DimTypeID})
Order By Identifier, ClassCode

SELECT COUNT(DISTINCT TI.ItemID) as count FROM XBOLTADM.TB_ITEM TI Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} WHERE TI.Deleted != 1
AND TI.ItemID IN ( SELECT DISTINCT ItemID FROM XBOLTADM.TB_ITEM_ATTR WHERE AttrTypeCode in ( SELECT AttrTypeCode FROM XBOLTADM.TB_ATTR_TYPE_ALLOCATION WHERE ItemClassCode = #{ClassCode} ) AND PlainText
not
like '%'+#{searchValue}+'%' )
AND TI.ClassCode = #{ClassCode}
AND TI.ItemTypeCode = #{ItemTypeCode}
AND TIA.PlainText like '%'+#{searchValue}+'%'
AND TI.ClassCode = #{ClassCode}
AND TI.ItemTypeCode = #{ItemTypeCode}

SELECT Distinct
	TATA.AttrTypeCode AS CODE
	, TD.Name AS NAME
FROM 
	XBOLTADM.TB_ATTR_TYPE_ALLOCATION TATA
	Left outer Join XBOLTADM.TB_DICTIONARY TD
		on TATA.AttrTypeCode = TD.TypeCode
		AND TD.LanguageID = #{languageID} 

	
		AND TATA.ItemTypeCode = #{s_itemID}
	
	
		AND TATA.ItemClassCode = #{s_itemID2}

		SELECT LovCode AS CODE
      		, Value AS NAME
      	FROM XBOLTADM.TB_ATTR_TYPE_LOV
  		WHERE AttrTypeCode = #{AttrTypeCode}
  		AND LanguageID = #{LanguageID}

		SELECT DataType, ISNULL(IsComLang, '') AS IsComLang
     	FROM XBOLTADM.TB_ATTR_TYPE
  		WHERE AttrTypeCode = #{AttrTypeCode}

		SELECT Distinct T1.SymTypeCode As CODE
			, T2.Name As NAME
      	FROM XBOLTADM.TB_SYMBOL_TYPE T1
		Left outer join XBOLTADM.TB_DICTIONARY T2 on T1.SymTypeCode = T2.TypeCode AND T2.LanguageID = #{languageID}
		WHERE T2.Name is not null AND T1.Deactivated != 1		
			
				AND T1.ItemTypeCode = #{ItemTypeCode}

SELECT Top 1000 RNUM , 0 AS CHK , ItemTypeImg , ItemID, Path, ItemName, ClassName, ClassCode, TeamName , OwnerTeamName, Name, LastUpdated,Version, Identifier, CSVersion , ProcessInfo , ItemTypeName , ValidFrom , StatusName , 'btn_import_small.gif' As Report , CreationTime FROM ( SELECT Row_Number()OVER(ORDER BY TI.Identifier, TI.ClassCode) as RNUM , TI.ItemID , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , ISNULL(XBOLTADM.fn_GetMyAbsPathForList( TI.ItemID ,#{languageID}),'') AS Path , ISNULL(TIA.PlainText,'') as ItemName , TD.Name as ClassName, TI.ClassCode , ISNULL(TT.Name, '') as TeamName , TOT.Name as OwnerTeamName , TM.Name , TI.Version , TI.Identifier , TIAF.PlainText as ProcessInfo , TSD.Name AS StatusName , TID.Name AS ItemTypeName , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated , Convert(nvarchar(20),TI.CreationTime, 111) AS CreationTime , Convert(nvarchar(20),TCS.ValidFrom, 111) AS ValidFrom , TCS.Version AS CSVersion , ISNULL(TIA.PlainText,'') as HostDeptTeamName FROM XBOLTADM.TB_ITEM TI
Left Outer JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} Left outer join XBOLTADM.TB_DICTIONARY TSD on TI.Status = TSD.TypeCode AND TSD.LanguageID = #{languageID} AND TSD.Category = 'ITMSTS' Left outer join XBOLTADM.TB_DICTIONARY TID on TI.ItemTypeCode = TID.TypeCode AND TID.LanguageID = #{languageID} Left outer join XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID} Left outer join XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} Left outer join XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} Left outer join XBOLTADM.TB_ITEM_ATTR TIAF on TI.ItemID = TIAF.ItemID AND TIAF.AttrTypeCode = 'AT00003' AND TIAF.LanguageID = #{languageID} Left outer join XBOLTADM.TB_ITEM_ATTR TIA2 on TI.ItemID = TIA2.ItemID AND TIA2.AttrTypeCode = 'AT00053' AND TIA2.LanguageID = #{languageID} Left outer join XBOLTADM.TB_CHANGE_SET TCS on TI.CurChangeSet = TCS.ChangeSetID LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TCLS ON TCLS.ItemClassCode = TI.ClassCode
WHERE TI.Deleted != 1
AND (1=1
${item.selectOption} TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM_ATTR WHERE AttrTypeCode = #{item.attrCode}
AND REPLACE(PlainText,' ','')
NOT like replace('%'+#{item.searchValue}+'%', ' ','')
AND REPLACE(PlainText,' ','')
not like replace('%'+#{item.searchValue}+'%'ESCAPE'!', ' ','')
AND LanguageID = #{languageID}
AND LanguageID = #{defaultLang}
)
${item.selectOption} TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM_ATTR WHERE LovCode IN (
#{item2}
) AND AttrTypeCode = #{item.attrCode}
AND LanguageID = #{languageID}
AND LanguageID = #{defaultLang}
)
${item.selectOption} TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM WHERE Identifier
not
like '%'+#{item.searchValue}+'%' )
AND TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM_ATTR WHERE AttrTypeCode = #{item.attrCode} AND LanguageID = #{languageID}
AND ClassCode = #{ClassCode}
AND ItemID IN(${childItems})
AND ItemID IN ('')
)
AND TI.ItemID NOT IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM_ATTR WHERE AttrTypeCode = #{item.attrCode} AND LanguageID = #{languageID}
AND ClassCode = #{ClassCode}
AND ItemID IN (${childItems})
AND ItemID IN ('')
)
)
AND TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM_ATTR WHERE REPLACE(PlainText,' ','') like REPLACE('%'+#{baseCondition1}+'%',' ','') AND AttrTypeCode = #{AttrCodeBase1} AND LanguageID = #{languageID} )
AND TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM WHERE
Identifier like '%'+#{baseCondition2}+'%'ESCAPE'!' Identifier like '%'+#{baseCondition2}+'%'
)
AND TI.CategoryCode = #{CategoryCode}
AND TI.ClassCode = #{ClassCode}
AND TI.ItemTypeCode = #{ItemTypeCode}
AND TCLS.ChangeMgt = #{changeMgt}
AND TI.ItemID IN (${childItems})
AND TI.ItemID IN ('')
AND TI.ItemID NOT IN (${masterItemId})
AND TI.ItemID IN ( Select ItemID From XBOLTADM.TB_ITEM_DIM WHERE DimTypeID = #{DimTypeID}
AND DimValueID IN (
#{item}
)
)
AND TIDM.DimValueID IS NULL
AND TI.CompanyID = #{CompanyID}
AND TOT.Name like '%'+#{OwnerTeam}+'%'ESCAPE'!'
AND TOT.Name like '%'+#{OwnerTeam}+'%'
AND TM.Name like '%'+#{Name}+'%'ESCAPE'!'
AND TM.Name like '%'+#{Name}+'%'
AND TI.Status = #{Status}
AND TI.Identifier IS NOT NULL AND TI.Identifier != ''
AND CONVERT(nvarchar(20), TI.CreationTime, 112) BETWEEN #{scStartDt1} AND #{scEndDt1}
AND CONVERT(nvarchar(20), TI.LastUpdated, 112) BETWEEN #{scStartDt2} AND #{scEndDt2}
AND DATEDIFF(YY,TI.LastUpdated,GETDATE()) > 1 AND TI.ClassCode IN (${ClassCodes}) AND TI.ItemTypeCode IN (${ItemTypeCodes})
And TI.AuthorID = #{sessionUserId}
) A 1=1
AND A.RNUM BETWEEN ((${pageNo}-1)*${LIST_PAGE_SCALE} + 1) AND (${pageNo}*${LIST_PAGE_SCALE})
AND ItemID NOT IN (select ItemID FROM XBOLTADM.TB_ITEM_DIM WHERE DimTypeID = #{DimTypeID})
Order By Identifier, ClassCode

SELECT Top 1000 Row_Number()OVER(ORDER BY VisitTime DESC, Identifier, ClassCode) as RNUM , 0 AS CHK , ItemTypeImg , ItemID, Path, ItemName, ClassName, ClassCode, TeamName , OwnerTeamName, Name, LastUpdated,Identifier, CSVersion , ProcessInfo , ItemTypeName , ValidFrom , StatusName , 'btn_import_small.gif' As Report , CreationTime , DefArc , ArcStyle , ArcIcon , ArcURL , MenuVar , ArcVar FROM ( SELECT TI.ItemID , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg , ISNULL(XBOLTADM.fn_GetMyAbsPathForList( TI.ItemID ,#{languageID}),'') AS Path , ISNULL(TIA.PlainText,'') as ItemName , TD.Name as ClassName, TI.ClassCode , ISNULL(TT.Name, '') as TeamName , TOT.Name as OwnerTeamName , TM.Name , TI.Identifier , TIAF.PlainText as ProcessInfo , TSD.Name AS StatusName , TID.Name AS ItemTypeName , Convert(nvarchar(20),TI.LastUpdated, 111) AS LastUpdated , Convert(nvarchar(20),TI.CreationTime, 111) AS CreationTime , Convert(nvarchar(20),TCS.ValidFrom, 111) AS ValidFrom , TCS.Version AS CSVersion , ISNULL(TIA.PlainText,'') as HostDeptTeamName , ISNULL(TIT.DefArc,'') AS DefArc , TA.Style AS ArcStyle , TA.Icon AS ArcIcon , TMU.URL AS ArcURL , TMU.VarFilter AS MenuVar , TA.VarFilter AS ArcVar , TI.VisitTime FROM (SELECT MAX(TVL.Time) AS VisitTime, TI.ItemTypeCode, TI.ClassCode, TI.Status, TI.CompanyID, TI.CreationTime, TI.OwnerTeamID, TI.AuthorID, TI.ItemID, TI.CurChangeSet, TI.Identifier, TI.LastUpdated FROM XBOLTADM.TB_VISIT_LOG TVL Left Outer Join XBOLTADM.TB_ITEM TI ON TVL.ItemID = TI.ItemID WHERE TVL.MemberID = #{memberID} AND TVL.ITEMID IS NOT NULL AND TVL.ActionType IS NULL AND TI.CategoryCode = 'OJ' AND TI.Deleted != 1 GROUP BY TI.ItemTypeCode, TI.ClassCode, TI.Status, TI.CompanyID, TI.CreationTime, TI.OwnerTeamID, TI.AuthorID, TI.ItemID, TI.CurChangeSet, TI.Identifier, TI.LastUpdated )TI Left Outer JOIN XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode Left Outer JOIN XBOLTADM.TB_ITEM_CLASS TIC ON TI.ClassCode = TIC.ItemClassCode Left outer join XBOLTADM.TB_DICTIONARY TD on TI.ClassCode = TD.TypeCode AND TD.LanguageID = #{languageID} Left outer join XBOLTADM.TB_DICTIONARY TSD on TI.Status = TSD.TypeCode AND TSD.LanguageID = #{languageID} AND TSD.Category = 'ITMSTS' Left outer join XBOLTADM.TB_DICTIONARY TID on TI.ItemTypeCode = TID.TypeCode AND TID.LanguageID = #{languageID} Left outer join XBOLTADM.TB_TEAM_TXT TT on TI.CompanyID = TT.TeamID AND TT.LanguageID = #{languageID} Left outer join XBOLTADM.TB_TEAM_TXT TOT on TI.OwnerTeamID = TOT.TeamID AND TOT.LanguageID = #{languageID} Left outer join XBOLTADM.TB_MEMBER TM on TI.AuthorID = TM.MemberID Left outer join XBOLTADM.TB_ITEM_ATTR TIA on TI.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} Left outer join XBOLTADM.TB_ITEM_ATTR TIAF on TI.ItemID = TIAF.ItemID AND TIAF.AttrTypeCode = 'AT00003' AND TIAF.LanguageID = #{languageID} Left outer join XBOLTADM.TB_ITEM_ATTR TIA2 on TI.ItemID = TIA2.ItemID AND TIA2.AttrTypeCode = 'AT00053' AND TIA2.LanguageID = #{languageID} Left outer join XBOLTADM.TB_CHANGE_SET TCS on TI.CurChangeSet = TCS.ChangeSetID Left Outer Join XBOLTADM.TB_ARC TA ON TA.ArcCode = TIT.DefArc Left Outer Join XBOLTADM.TB_MENU TMU ON TA.MenuID = TMU.MenuID WHERE TIC.ChangeMgt = 1
AND TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM_ATTR WHERE REPLACE(PlainText,' ','') like REPLACE('%'+#{detailNm}+'%',' ','') AND AttrTypeCode = 'AT00001' AND LanguageID = #{languageID} )
AND TI.ItemID IN ( SELECT ItemID FROM XBOLTADM.TB_ITEM WHEREIdentifier like '%'+#{detailID}+'%'ESCAPE'!' )
AND TI.ClassCode = #{ClassCode}
AND TM.Name like '%'+#{Name}+'%'ESCAPE'!'
AND TM.Name like '%'+#{Name}+'%'
AND TI.Status = #{Status}
AND CONVERT(nvarchar(20), TVL.Time, 112) BETWEEN #{lvStartDt} AND #{lvEndDt}
) A 1=1
AND A.RNUM BETWEEN ((${pageNo}-1)*${LIST_PAGE_SCALE} + 1) AND (${pageNo}*${LIST_PAGE_SCALE})
Order By RNUM
